import React, { useState, useEffect } from 'react';
import Layout from '../components/shared/Layout';
import { PlatformIcons, PLATFORMS, formatKPI } from '../utils/platforms';
import api from '../utils/api';

export default function AdSpendPage() {
  const [invoices, setInvoices] = useState([]);
  const [platformStats, setPlatformStats] = useState([]);
  const [loading, setLoading] = useState(true);
  const [generating, setGenerating] = useState(false);
  const [addFundsModal, setAddFundsModal] = useState(null);
  const [amount, setAmount] = useState('');
  const [toast, setToast] = useState('');
  const [activeTab, setActiveTab] = useState('overview');

  const showToast = msg => { setToast(msg); setTimeout(()=>setToast(''),4000); };

  useEffect(() => { fetchData(); }, []);

  const fetchData = async () => {
    try {
      const [invRes, analyticsRes] = await Promise.all([
        api.get('/invoices'),
        api.get('/analytics/platform-performance')
      ]);
      setInvoices(invRes.data.invoices || []);
      setPlatformStats(invRes.data || { invoices:[], totalPaid:0 });
    } catch { } finally { setLoading(false); }
  };

  const handleGenerateInvoices = async () => {
    setGenerating(true);
    try {
      const start = new Date(Date.now()-30*86400000).toISOString();
      const end = new Date().toISOString();
      const res = await api.post('/invoices/generate', { period:{ start, end } });
      showToast(`✅ Generated ${res.data.created} invoice${res.data.created!==1?'s':''} from campaign spend data`);
      fetchData();
    } catch (err) { showToast('❌ '+err.message); }
    finally { setGenerating(false); }
  };

  // Aggregate spend by platform from invoices
  const byPlatform = PLATFORMS.map(pl => {
    const plInvoices = invoices.filter(i=>i.platform===pl.id);
    const spent = plInvoices.reduce((s,i)=>s+(i.status==='paid'?i.amount:0),0);
    const pending = plInvoices.reduce((s,i)=>s+(i.status==='pending'?i.amount:0),0);
    return { ...pl, spent, pending, invoiceCount: plInvoices.length };
  }).filter(p=>p.invoiceCount>0||p.spent>0);

  const totalSpent = invoices.reduce((s,i)=>s+(i.status==='paid'?i.amount:0),0);
  const totalPending = invoices.reduce((s,i)=>s+(i.status==='pending'?i.amount:0),0);

  return (
    <Layout>
      {toast && (
        <div style={{ position:'fixed',top:20,right:20,zIndex:9999,padding:'13px 18px',borderRadius:12,background:'var(--bg-card)',border:'1px solid var(--border-subtle)',boxShadow:'0 8px 32px rgba(0,0,0,0.2)',fontSize:13,color:'var(--text-primary)',animation:'slideIn 0.3s ease-out',maxWidth:380 }}>
          {toast}
        </div>
      )}

      <div className="page-header">
        <div>
          <h1 className="page-title">Ad Spend</h1>
          <p className="page-subtitle">Track advertising expenditure across all platforms</p>
        </div>
        <div style={{ display:'flex',gap:10 }}>
          <button className="btn-secondary" onClick={handleGenerateInvoices} disabled={generating} style={{ fontSize:13 }}>
            {generating?'Generating...':'🧾 Generate Invoices'}
          </button>
          <button className="btn-primary" onClick={()=>setAddFundsModal('all')} style={{ fontSize:13 }}>
            + Add Funds
          </button>
        </div>
      </div>

      {/* Summary */}
      <div style={{ display:'grid',gridTemplateColumns:'repeat(auto-fit,minmax(160px,1fr))',gap:14,marginBottom:28 }}>
        {[
          { label:'Total Spent',   value:formatKPI(totalSpent,'currency'),   icon:'💸', color:'#ef4444' },
          { label:'Pending',       value:formatKPI(totalPending,'currency'), icon:'⏳', color:'#d97706' },
          { label:'Invoices',      value:invoices.length,                    icon:'🧾', color:'#3b82f6' },
          { label:'Platforms',     value:byPlatform.length||PLATFORMS.length,icon:'📡', color:'#7c3aed' },
        ].map(s=>(
          <div key={s.label} className="glass-card" style={{ padding:'18px 20px' }}>
            <div style={{ fontSize:22,marginBottom:8 }}>{s.icon}</div>
            <div style={{ fontSize:22,fontWeight:800,color:s.color,marginBottom:4 }}>{s.value}</div>
            <div style={{ fontSize:12,color:'var(--text-muted)',fontWeight:600 }}>{s.label}</div>
          </div>
        ))}
      </div>

      {/* Tabs */}
      <div style={{ display:'flex',gap:4,marginBottom:20,background:'var(--bg-elevated)',borderRadius:12,padding:4,width:'fit-content' }}>
        {['overview','invoices'].map(tab=>(
          <button key={tab} onClick={()=>setActiveTab(tab)} style={{ padding:'8px 20px',borderRadius:9,border:'none',fontSize:13,fontWeight:600,cursor:'pointer',fontFamily:'DM Sans,sans-serif',textTransform:'capitalize',
            background:activeTab===tab?'var(--bg-card)':'transparent',
            color:activeTab===tab?'var(--text-primary)':'var(--text-faint)',
            boxShadow:activeTab===tab?'0 2px 8px rgba(0,0,0,0.1)':'none',
            transition:'all 0.2s' }}>
            {tab}
          </button>
        ))}
      </div>

      {loading ? (
        <div style={{ display:'flex',flexDirection:'column',gap:12 }}>
          {[1,2,3].map(i=><div key={i} className="skeleton" style={{ height:80,borderRadius:12 }}/>)}
        </div>
      ) : activeTab==='overview' ? (
        <>
          {byPlatform.length === 0 ? (
            <div className="glass-card" style={{ padding:48,textAlign:'center' }}>
              <div style={{ fontSize:48,marginBottom:16 }}>💳</div>
              <h3 style={{ fontSize:18,fontWeight:700,color:'var(--text-primary)',margin:'0 0 8px' }}>No Spend Data Yet</h3>
              <p style={{ fontSize:13,color:'var(--text-muted)',margin:'0 0 24px',lineHeight:1.7,maxWidth:420,marginInline:'auto' }}>
                Click <strong>Generate Invoices</strong> to create spend records from your campaign data, or connect a platform and sync to pull real spend data.
              </p>
              <button className="btn-primary" onClick={handleGenerateInvoices} disabled={generating}>
                🧾 Generate from Campaign Data
              </button>
            </div>
          ) : (
            <div style={{ display:'grid',gridTemplateColumns:'repeat(auto-fill,minmax(280px,1fr))',gap:16 }}>
              {byPlatform.map(p=>{
                const Icon = PlatformIcons[p.id];
                return (
                  <div key={p.id} className="glass-card" style={{ padding:22,border:`1px solid ${p.color}33` }}>
                    <div style={{ display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:16 }}>
                      <div style={{ display:'flex',alignItems:'center',gap:10 }}>
                        {Icon && <Icon size={26}/>}
                        <div>
                          <div style={{ fontWeight:700,fontSize:15,color:'var(--text-primary)' }}>{p.name}</div>
                          <div style={{ fontSize:11,color:'var(--text-faint)' }}>{p.invoiceCount} invoice{p.invoiceCount!==1?'s':''}</div>
                        </div>
                      </div>
                      <button onClick={()=>setAddFundsModal(p.id)} className="btn-secondary" style={{ fontSize:11,padding:'5px 10px' }}>+ Add</button>
                    </div>
                    <div style={{ display:'grid',gridTemplateColumns:'1fr 1fr',gap:10 }}>
                      <div style={{ padding:'10px 12px',borderRadius:10,background:'var(--bg-elevated)' }}>
                        <div style={{ fontSize:10,color:'var(--text-faint)',marginBottom:3 }}>SPENT</div>
                        <div style={{ fontSize:16,fontWeight:800,color:'#ef4444' }}>{formatKPI(p.spent,'currency')}</div>
                      </div>
                      <div style={{ padding:'10px 12px',borderRadius:10,background:'var(--bg-elevated)' }}>
                        <div style={{ fontSize:10,color:'var(--text-faint)',marginBottom:3 }}>PENDING</div>
                        <div style={{ fontSize:16,fontWeight:800,color:'#d97706' }}>{formatKPI(p.pending,'currency')}</div>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </>
      ) : (
        /* Invoices tab */
        <div className="glass-card" style={{ padding:24 }}>
          <h3 style={{ fontSize:16,fontWeight:700,color:'var(--text-primary)',margin:'0 0 20px' }}>
            Invoice History ({invoices.length})
          </h3>
          {invoices.length === 0 ? (
            <div style={{ textAlign:'center',padding:'36px 20px',color:'var(--text-muted)' }}>
              <div style={{ fontSize:40,marginBottom:12 }}>🧾</div>
              <div>No invoices yet. Click "Generate Invoices" to create them from campaign data.</div>
            </div>
          ) : (
            <div className="responsive-table">
              <table style={{ width:'100%',borderCollapse:'collapse' }}>
                <thead>
                  <tr>
                    {['Invoice #','Platform','Period','Amount','Status','Date'].map(h=>(
                      <th key={h} style={{ padding:'8px 14px',textAlign:'left',fontSize:11,color:'var(--text-faint)',fontWeight:700,textTransform:'uppercase',letterSpacing:'0.05em',borderBottom:'1px solid var(--border-subtle)',whiteSpace:'nowrap' }}>{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {invoices.map(inv=>{
                    const Icon = PlatformIcons[inv.platform];
                    const pl = PLATFORMS.find(p=>p.id===inv.platform);
                    return (
                      <tr key={inv._id} style={{ borderBottom:'1px solid var(--border-subtle)' }}>
                        <td style={{ padding:'12px 14px',fontSize:12,fontWeight:600,color:'var(--text-primary)',fontFamily:'DM Mono,monospace' }}>{inv.invoiceNumber}</td>
                        <td style={{ padding:'12px 14px' }}>
                          <div style={{ display:'flex',alignItems:'center',gap:8 }}>
                            {Icon && <Icon size={16}/>}
                            <span style={{ fontSize:12,color:'var(--text-secondary)',fontWeight:600 }}>{pl?.name||inv.platform}</span>
                          </div>
                        </td>
                        <td style={{ padding:'12px 14px',fontSize:12,color:'var(--text-muted)',whiteSpace:'nowrap' }}>
                          {inv.period?.start?new Date(inv.period.start).toLocaleDateString():'—'} – {inv.period?.end?new Date(inv.period.end).toLocaleDateString():'—'}
                        </td>
                        <td style={{ padding:'12px 14px',fontSize:13,fontWeight:800,color:'var(--text-primary)' }}>
                          ${inv.amount?.toFixed(2)}
                        </td>
                        <td style={{ padding:'12px 14px' }}>
                          <span className={`status-${inv.status==='paid'?'active':inv.status==='pending'?'paused':'draft'}`} style={{ fontSize:10 }}>
                            {inv.status?.toUpperCase()}
                          </span>
                        </td>
                        <td style={{ padding:'12px 14px',fontSize:12,color:'var(--text-muted)',whiteSpace:'nowrap' }}>
                          {new Date(inv.createdAt).toLocaleDateString()}
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}
        </div>
      )}

      {/* Add Funds Modal */}
      {addFundsModal && (
        <div style={{ position:'fixed',inset:0,background:'rgba(0,0,0,0.65)',zIndex:2000,display:'flex',alignItems:'center',justifyContent:'center',padding:20 }} onClick={()=>setAddFundsModal(null)}>
          <div className="glass-card" style={{ padding:32,maxWidth:440,width:'100%' }} onClick={e=>e.stopPropagation()}>
            <h3 style={{ fontSize:18,fontWeight:800,color:'var(--text-primary)',margin:'0 0 6px' }}>Add Ad Funds</h3>
            <p style={{ fontSize:13,color:'var(--text-muted)',margin:'0 0 20px' }}>
              {addFundsModal==='all'?'Top up funds across platforms':'Top up '+PLATFORMS.find(p=>p.id===addFundsModal)?.name}
            </p>
            <label className="form-label">Amount (USD)</label>
            <input className="form-input" type="number" placeholder="500.00" value={amount} onChange={e=>setAmount(e.target.value)} style={{ marginBottom:14 }}/>
            <label className="form-label">Payment Method</label>
            <select className="form-input" style={{ marginBottom:22 }}>
              <option>Visa ••••4242</option>
              <option>Add new card...</option>
            </select>
            <div style={{ padding:'12px 14px',borderRadius:10,background:'rgba(124,58,237,0.07)',border:'1px solid rgba(124,58,237,0.2)',fontSize:12,color:'var(--text-muted)',marginBottom:20,lineHeight:1.6 }}>
              💡 Connect Stripe in your server <code style={{ background:'var(--bg-elevated)',padding:'1px 5px',borderRadius:4 }}>.env</code> to enable live payments: <code>STRIPE_SECRET_KEY=sk_live_...</code>
            </div>
            <div style={{ display:'flex',gap:10 }}>
              <button className="btn-secondary" onClick={()=>setAddFundsModal(null)} style={{ flex:1,justifyContent:'center' }}>Cancel</button>
              <button className="btn-primary" onClick={()=>{showToast('💳 In production this charges your card and tops up the platform ad account.');setAddFundsModal(null);}} style={{ flex:2,justifyContent:'center' }}>
                💳 Add ${amount||'0'}
              </button>
            </div>
          </div>
        </div>
      )}
    </Layout>
  );
}
